#include<bits/stdc++.h>
using namespace std;
int n,tot_leaf,tot_node,tot_segtree;
int p[4000010],ll[4000010],rr[4000010],lson[4000010],rson[4000010],root[4000010];
long long ans;
struct segtree_node
{
    int lson,rson;
    int sum;
}t[40000010];
stack<int> s;
int build_tree()
{
    int x=++tot_node;
    int v;
    scanf("%d",&v);
    if(v!=0)
    {
        p[++tot_leaf]=v;
        ll[x]=rr[x]=tot_leaf;
        return x;
    }
    lson[x]=build_tree();
    rson[x]=build_tree();
    ll[x]=ll[lson[x]];
    rr[x]=rr[rson[x]];
    return x;
}
void add(int &x,int l,int r,int p,int v)
{
    if(!x)
    {
        if(!s.empty())
        {
            x=s.top();
            s.pop();
        }
        else
        {
            x=++tot_segtree;
        }
        t[x].lson=t[x].rson=t[x].sum=0;
    }
    t[x].sum+=v;
    if(l==r)
    {
        return;
    }
    int mid=(l+r)>>1;
    if(p<=mid)
    {
        add(t[x].lson,l,mid,p,v);
    }
    else
    {
        add(t[x].rson,mid+1,r,p,v);
    }
}
int getsum(int x,int l,int r,int u,int v)
{
    if(!x||l>v||u>v||r<u)
    {
        return 0;
    }
    if(u<=l&&r<=v)
    {
        return t[x].sum;
    }
    int mid=(l+r)>>1;
    return getsum(t[x].lson,l,mid,u,v)+getsum(t[x].rson,mid+1,r,u,v);
}
int merge(int x,int y,int l,int r)
{
    if(x==0||y==0)
    {
        return x+y;
    }
    t[x].sum+=t[y].sum;
    if(l==r)
    {
        s.push(y);
        return x;
    }
    int mid=(l+r)>>1;
    t[x].lson=merge(t[x].lson,t[y].lson,l,mid);
    t[x].rson=merge(t[x].rson,t[y].rson,mid+1,r);
    s.push(y);
    return x;
}
void dfs(int x)
{
    if(lson[x]==0&&rson[x]==0)
    {
        add(root[x],1,n,p[ll[x]],1);
        return;
    }
    dfs(lson[x]);
    dfs(rson[x]);
    if(rr[lson[x]]-ll[lson[x]]>rr[rson[x]]-ll[rson[x]])
    {
        swap(lson[x],rson[x]);
    }
    long long sum1=0,sum2=0;
    for(int i=ll[lson[x]];i<=rr[lson[x]];i++)
    {
        sum1+=getsum(root[rson[x]],1,n,1,p[i]-1);
    }
    for(int i=ll[lson[x]];i<=rr[lson[x]];i++)
    {
        sum2+=getsum(root[rson[x]],1,n,p[i]+1,n);
    }
    ans+=min(sum1,sum2);
    root[x]=merge(root[lson[x]],root[rson[x]],1,n);
}
int main()
{
    scanf("%d",&n);
    build_tree();
    dfs(1);
    printf("%lld",ans);
    return 0;
}
